// Merge all health data into a single report
const services = JSON.parse($input.all()[0].json.stdout || '[]');
const ollama = JSON.parse($input.all()[1].json.stdout || '{}');
const stats = JSON.parse($input.all()[2].json.stdout || '{}');

const now = new Date().toISOString();

// Check for any issues
const issues = [];
const servicesArr = Array.isArray(services) ? services : [services];
for (const svc of servicesArr) {
  if (svc.Status !== 'Running') {
    issues.push(`Service ${svc.Name} is ${svc.Status}`);
  }
}
if (ollama.Status !== 'Running') {
  issues.push('Ollama is down');
}
if (stats.Disk_GB && stats.Disk_GB.UsedPct > 85) {
  issues.push(`Disk usage critical: ${stats.Disk_GB.UsedPct}%`);
}
if (stats.CPU > 90) {
  issues.push(`CPU usage high: ${stats.CPU}%`);
}

const health = {
  timestamp: now,
  status: issues.length === 0 ? 'HEALTHY' : 'DEGRADED',
  issues: issues,
  services: servicesArr,
  ollama: ollama,
  system: stats,
  needsRestart: servicesArr.some(s => s.Status !== 'Running'),
  needsCleanup: stats.Disk_GB && stats.Disk_GB.UsedPct > 85
};

return [{ json: health }];
